static int snapshot(PinState*s){memset(s,0,sizeof(*s));char p[160];for(int c=0;c<NCPU;c++){snprintf(p,sizeof(p),"/sys/devices/system/cpu/cpu%d/cpufreq/scaling_min_freq",c);if(read_long(p,&s->min[c]))return-1;snprintf(p,sizeof(p),"/sys/devices/system/cpu/cpu%d/cpufreq/scaling_max_freq",c);if(read_long(p,&s->max[c]))return-1;s->have[c]=1;}if(!read_long("/sys/devices/system/cpu/cpufreq/boost",&s->boost))s->boost_have=1;return 0;}
static int pin_frequency(PinState*s,long khz){char a[160],b[160];if(s->boost_have&&write_long("/sys/devices/system/cpu/cpufreq/boost",0))return-1;for(int c=0;c<NCPU;c++){snprintf(a,sizeof(a),"/sys/devices/system/cpu/cpu%d/cpufreq/scaling_min_freq",c);snprintf(b,sizeof(b),"/sys/devices/system/cpu/cpu%d/cpufreq/scaling_max_freq",c);if(write_long(a,khz<s->max[c]?khz:s->max[c])||write_long(b,khz)||write_long(a,khz))return-1;long x,y;if(read_long(a,&x)||read_long(b,&y)||x!=khz||y!=khz)return-1;}s->changed=1;return 0;}
