static double calibrate_tsc(void){struct timespec a,b,s={0,50000000};clock_gettime(CLOCK_MONOTONIC_RAW,&a);uint64_t x=rdtsc_now();nanosleep(&s,NULL);uint64_t y=rdtsc_now();clock_gettime(CLOCK_MONOTONIC_RAW,&b);double dt=(b.tv_sec-a.tv_sec)+(b.tv_nsec-a.tv_nsec)*1e-9;return dt>0?(y-x)/dt:0;}
static double alu_burst(uint64_t*s){double a=1.000001;uint64_t x=*s;for(int i=0;i<64;i++){a=a*1.00000007+.99999993;x=x*6364136223846793005ULL+1;}*s=x;return a+(x&255);}
typedef struct {atomic_int stop;pthread_t thread;int alive,core,level;uint64_t origin;double half_ticks,phase;} Sender;
static void*sender_loop(void*v){Sender*d=v;if(pin_core(d->core))return(void*)1;uint64_t seed=0x9e3779b9u+d->core;volatile double sink=0;double period=2*d->half_ticks;while(!atomic_load(&d->stop)){double z=(double)(rdtsc_now()-d->origin)-d->phase*period;long half=(long)floor(z/d->half_ticks);int quadrant=(int)((half%8+8)%8);if(quadrant<d->level*2)sink+=alu_burst(&seed);else __asm__ volatile("pause");}return(void*)(uintptr_t)(sink!=sink);}
static int sender_start(Sender*d,int core,uint64_t origin,double tone,double tsc,int phase,int level){memset(d,0,sizeof(*d));d->core=core;d->origin=origin;d->half_ticks=.5*tsc/tone;d->phase=phase/8.0;d->level=level<1?1:(level>3?3:level);atomic_init(&d->stop,0);pthread_attr_t a;pthread_attr_init(&a);cpu_set_t s;CPU_ZERO(&s);CPU_SET(core,&s);pthread_attr_setaffinity_np(&a,sizeof(s),&s);int r=pthread_create(&d->thread,&a,sender_loop,d);pthread_attr_destroy(&a);if(r)return-1;d->alive=1;return 0;}
static int sender_stop(Sender*d){if(!d->alive)return 0;if(!d->thread){d->alive=0;return 0;}atomic_store(&d->stop,1);struct timespec t;clock_gettime(CLOCK_REALTIME,&t);t.tv_sec+=2;void*rv=NULL;int r=pthread_timedjoin_np(d->thread,&rv,&t);d->alive=0;return r||rv?-1:0;}
static int capture(int core,long hz,double seconds,double tsc,uint64_t*ts,double*ro,int cap){if(pin_core(core))return-1;uint64_t end=rdtsc_now()+(uint64_t)(seconds*tsc),prev=rdtscp_now(),acc=0x9e3779b9u+core;double span=tsc/hz;int n=0;while(n<cap&&rdtsc_now()<end&&!interrupted){uint64_t now,it=0;do{acc=acc*6364136223846793005ULL+1;it++;now=rdtscp_now();}while((double)(now-prev)<span);ts[n]=now;ro[n]=(double)(now-prev)/it;prev=now;n++;}return n;}
#define capture(core,hz,seconds,ts,ro,cap) capture((core),(hz),(seconds),tsc,(ts),(ro),(cap))
static void lockin(const uint64_t*t,const double*x,int n,double f,uint64_t o,double hz,double*I,double*Q,double*M,double*F){double mean=0;for(int i=0;i<n;i++)mean+=x[i];mean/=n;double a=0,b=0,c=0,d=0,w=0;for(int i=0;i<n;i++){double win=.5*(1-cos(2*M_PI*i/(n-1))),v=(x[i]-mean)*win,dt=(t[i]-o)/hz;a+=v*cos(2*M_PI*f*dt);b+=v*sin(2*M_PI*f*dt);c+=v*cos(2*M_PI*(f*1.37+.071)*dt);d+=v*sin(2*M_PI*(f*1.37+.071)*dt);w+=win;}*I=2*a/w;*Q=2*b/w;*M=hypot(*I,*Q);*F=2*hypot(c,d)/w;}
static double tone(int i){double lo=log(20),hi=log(1500),t=i/11.0;return exp(lo+(hi-lo)*t)*(1+.013*sin(2.399963*(i+1)));}
static int mode_index(const char*m){const char*x[]={"basis","rotation","residual","mini"};for(int i=0;i<4;i++)if(!strcmp(m,x[i]))return i;return-1;}
static int codebook[4][12],codebook_ready;
static uint64_t code_rng;
static uint64_t code_rand(void){uint64_t x=code_rng;x^=x<<13;x^=x>>7;x^=x<<17;return code_rng=x;}
static void make_codebook(void){int weights[4]={4,5,6,7},best[4][12],best_d=-1;code_rng=0x243F6A8885A308D3ULL^7ULL;for(int it=0;it<4000;it++){int c[4][12];for(int m=0;m<4;m++){int pool[12];for(int i=0;i<12;i++){c[m][i]=1;pool[i]=i;}for(int i=0;i<weights[m];i++){int j=i+(int)(code_rand()%(uint64_t)(12-i)),z=pool[i];pool[i]=pool[j];pool[j]=z;c[m][pool[i]]=-1;}}int d=99;for(int i=0;i<4;i++)for(int j=i+1;j<4;j++){int h=0;for(int k=0;k<12;k++)h+=c[i][k]!=c[j][k];if(h<d)d=h;}if(d>best_d){best_d=d;memcpy(best,c,sizeof(best));}}memcpy(codebook,best,sizeof(best));codebook_ready=1;}
static int code_sign(int m,int src){if(!codebook_ready)make_codebook();return m>=0&&src>=0&&src<12?codebook[m][src]:0;}
static int raw_record(FILE*f,uint64_t t,double x){unsigned char b[16];for(int i=0;i<8;i++)b[i]=(unsigned char)(t>>(8*i));uint64_t q;memcpy(&q,&x,8);for(int i=0;i<8;i++)b[8+i]=(unsigned char)(q>>(8*i));return fwrite(b,1,16,f)==16?0:-1;}
static void json_escape(FILE*f,const char*s){for(;*s;s++){if(*s=='\"'||*s=='\\')fputc('\\',f);fputc(*s,f);}}
static int append_provenance(const char*dir);
static int prepare_provenance(const char*dir){char p[CP_PATH_MAX],buf[2048];joinp(p,sizeof(p),dir,"run.json");FILE*f=fopen(p,"r+");if(!f)return-1;size_t n=fread(buf,1,sizeof(buf)-1,f);buf[n]=0;char*k=strstr(buf,"\"executor_git_commit\"");if(!k){fclose(f);return-1;}if(fseek(f,(long)(k-buf)+1,SEEK_SET)){fclose(f);return-1;}if(fwrite("executor_build_note",1,19,f)!=19){fclose(f);return-1;}if(fclose(f))return-1;return append_provenance(dir);}
static int provenance_appended=1;
#define append_provenance prepare_provenance
static int hash_file(const char*p,char out[65]){size_t z=strlen(p);if(!provenance_appended&&z>=8&&!strcmp(p+z-8,"run.json")){char dir[CP_PATH_MAX];if(z-9>=sizeof(dir))return-1;memcpy(dir,p,z-9);dir[z-9]=0;if(append_provenance(dir))return-1;provenance_appended=1;}char cmd[CP_PATH_MAX+32],line[128];if(snprintf(cmd,sizeof(cmd),"sha256sum '%s'",p)>=(int)sizeof(cmd))return-1;FILE*f=popen(cmd,"r");if(!f||!fgets(line,sizeof(line),f))return-1;int r=pclose(f);if(r)return-1;memcpy(out,line,64);out[64]=0;return 0;}
#undef append_provenance
static void cpu_model(char *out,size_t size){FILE*f=fopen("/proc/cpuinfo","r");char line[512];snprintf(out,size,"unknown");if(!f)return;while(fgets(line,sizeof(line),f)){if(!strncmp(line,"model name",10)){char*p=strchr(line,':');if(p){p++;while(*p==' '||*p=='\t')p++;p[strcspn(p,"\r\n")]=0;snprintf(out,size,"%s",p);}break;}}fclose(f);}
static int append_provenance(const char*dir){if(!provenance_args||!provenance_schedule||!provenance_pin)return 0;char p[CP_PATH_MAX],model[256];joinp(p,sizeof(p),dir,"run.json");FILE*f=fopen(p,"r+");if(!f||fseek(f,-2,SEEK_END)){if(f)fclose(f);return-1;}cpu_model(model,sizeof(model));fprintf(f,",\n  \"campaign_plan_sha256\": \"%s\",\n  \"session_manifest_sha256\": \"%s\",\n  \"executor_git_commit\": \"%s\",\n  \"cpu_model\": \"",provenance_schedule->campaign_plan_sha256,provenance_schedule->session_manifest_sha256,provenance_args->executor_commit);json_escape(f,model);fprintf(f,"\",\n  \"original_cpufreq_state\": {\"min_khz\": [");for(int c=0;c<NCPU;c++)fprintf(f,"%ld%s",provenance_pin->min[c],c+1<NCPU?", ":"");fprintf(f,"], \"max_khz\": [");for(int c=0;c<NCPU;c++)fprintf(f,"%ld%s",provenance_pin->max[c],c+1<NCPU?", ":"");fprintf(f,"], \"boost\": %ld},\n  \"applied_cpufreq_state\": {\"min_khz\": %ld, \"max_khz\": %ld, \"boost\": 0},\n  \"restored_cpufreq_state\": {\"verified\": %s, \"min_khz\": [",provenance_pin->boost,provenance_args->pin_khz,provenance_args->pin_khz,provenance_restored&&*provenance_restored?"true":"false");for(int c=0;c<NCPU;c++)fprintf(f,"%ld%s",provenance_pin->min[c],c+1<NCPU?", ":"");fprintf(f,"], \"max_khz\": [");for(int c=0;c<NCPU;c++)fprintf(f,"%ld%s",provenance_pin->max[c],c+1<NCPU?", ":"");fprintf(f,"], \"boost\": %ld}\n}\n",provenance_pin->boost);return fclose(f);}
static int seal_before_stat(const char*p){size_t z=strlen(p);if(!provenance_appended&&z>=8&&!strcmp(p+z-8,"run.json")){char dir[CP_PATH_MAX];if(z-9>=sizeof(dir))return-1;memcpy(dir,p,z-9);dir[z-9]=0;if(prepare_provenance(dir))return-1;provenance_appended=1;}return 0;}
#define stat(path,buf) (seal_before_stat(path), stat(path,buf))
int write_run_manifest(const char*dir,const char*sid,const char*status){const char*n[]={"run.json","session.json","windows.jsonl","window_results.csv","raw_samples.bin","telemetry.csv","stdout.log","stderr.log"};char p[CP_PATH_MAX];joinp(p,sizeof(p),dir,"run_manifest.json");FILE*f=fopen(p,"wx");if(!f)return-1;fprintf(f,"{\n  \"schema_id\": \"CAT_CAS_PHASE6_COMBINED_RUN_MANIFEST_V1\",\n  \"session_id\": \"");json_escape(f,sid);fprintf(f,"\",\n  \"status\": \"%s\",\n  \"files\": {\n",status);for(int i=0;i<8;i++){joinp(p,sizeof(p),dir,n[i]);struct stat s;char h[65];if(stat(p,&s)||hash_file(p,h)){fclose(f);return-1;}fprintf(f,"    \"%s\": {\"size\": %lld, \"sha256\": \"%s\"}%s\n",n[i],(long long)s.st_size,h,i==7?"":",");}fprintf(f,"  }\n}\n");return fclose(f);}
